// Przygotuj request do KlimtechRAG w formacie OpenAI
const body = $input.first().json.body || $input.first().json;

let userMessage = '';
let model = 'klimtech-bielik';
let useRag = true;
let webSearch = false;

// Obsługa różnych formatów wejściowych
if (body.messages) {
  // Format OpenAI — przekaż bezpośrednio
  return [{ json: {
    model: body.model || model,
    messages: body.messages,
    max_tokens: body.max_tokens || 4096,
    use_rag: body.use_rag !== undefined ? body.use_rag : useRag,
    web_search: body.web_search !== undefined ? body.web_search : webSearch
  }}];
} else if (body.question || body.message || body.text) {
  // Format prosty — zamień na OpenAI
  userMessage = body.question || body.message || body.text;
  return [{ json: {
    model: model,
    messages: [
      { role: 'system', content: 'Jesteś pomocnym asystentem AI z dostępem do bazy wiedzy RAG. Odpowiadaj po polsku.' },
      { role: 'user', content: userMessage }
    ],
    max_tokens: body.max_tokens || 4096,
    use_rag: useRag,
    web_search: webSearch
  }}];
}

throw new Error('Brak pola messages, question, message lub text w body');

// Wyciągnij odpowiedź z formatu OpenAI
const response = $input.first().json;
const answer = response.choices?.[0]?.message?.content || 'Brak odpowiedzi';
const model = response.model || 'unknown';
const usage = response.usage || {};

return [{ json: {
  answer: answer,
  model: model,
  usage: usage,
  timestamp: new Date().toISOString()
}}];
